import React, { useEffect, useState, useCallback } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getMatch, updateScore, getScorecard, addBattingPerformance, addBowlingPerformance, getPlayers } from '../services/api';

const DISMISSAL_TYPES = ['Bowled', 'Caught', 'LBW', 'Run Out', 'Stumped', 'Hit Wicket', 'Retired Hurt'];

export default function LiveScoring() {
  const { id } = useParams();
  const [match, setMatch] = useState(null);
  const [scorecard, setScorecard] = useState(null);
  const [team1Players, setTeam1Players] = useState([]);
  const [team2Players, setTeam2Players] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeInnings, setActiveInnings] = useState('FIRST');
  const [saving, setSaving] = useState(false);
  const [showBatModal, setShowBatModal] = useState(false);
  const [showBowlModal, setShowBowlModal] = useState(false);
  const [showScoreModal, setShowScoreModal] = useState(false);
  const [msg, setMsg] = useState('');
  const [autoRefresh, setAutoRefresh] = useState(true);
  const [lastEvents, setLastEvents] = useState([]);

  const [batForm, setBatForm] = useState({
    playerId: '', runs: 0, balls: 0, fours: 0, sixes: 0,
    isOut: false, dismissalType: 'Bowled', battingOrder: 1, inningsType: 'FIRST'
  });
  const [bowlForm, setBowlForm] = useState({
    playerId: '', overs: 0, maidens: 0, runsConceded: 0, wickets: 0,
    wides: 0, noBalls: 0, inningsType: 'FIRST'
  });
  const [scoreForm, setScoreForm] = useState({
    team1Score: '', team1Wickets: '', team1Overs: '',
    team2Score: '', team2Wickets: '', team2Overs: '',
    status: 'LIVE', tossWinnerId: '', tossDecision: 'BAT',
    winnerId: '', result: '', playerOfMatchId: ''
  });

  const loadAll = useCallback(() => {
    Promise.all([getMatch(id), getScorecard(id)]).then(([mr, sr]) => {
      setMatch(mr.data);
      setScorecard(sr.data);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, [id]);

  useEffect(() => {
    loadAll();
    getMatch(id).then(mr => {
      getPlayers(mr.data.team1Id).then(r => setTeam1Players(r.data));
      getPlayers(mr.data.team2Id).then(r => setTeam2Players(r.data));
    });
  }, [id, loadAll]);

  useEffect(() => {
    if (!autoRefresh) return;
    const interval = setInterval(() => {
      if (match?.status === 'LIVE') loadAll();
    }, 30000);
    return () => clearInterval(interval);
  }, [match?.status, autoRefresh, loadAll]);

  const showMsg = (m) => { setMsg(m); setTimeout(() => setMsg(''), 3000); };

  const addEvent = (label, runs) => {
    setLastEvents(prev => [...prev.slice(-5), { label, runs, time: new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }) }]);
  };

  const handleScoreUpdate = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      if (scoreForm.team1Score !== '') {
        await updateScore(id, {
          team: 'team1', score: +scoreForm.team1Score,
          wickets: +scoreForm.team1Wickets || 0, overs: +scoreForm.team1Overs || 0,
          status: scoreForm.status, tossWinnerId: scoreForm.tossWinnerId || undefined,
          tossDecision: scoreForm.tossDecision, result: scoreForm.result || undefined,
          winnerId: scoreForm.winnerId ? +scoreForm.winnerId : undefined,
          playerOfMatchId: scoreForm.playerOfMatchId ? +scoreForm.playerOfMatchId : undefined,
        });
      }
      if (scoreForm.team2Score !== '') {
        await updateScore(id, {
          team: 'team2', score: +scoreForm.team2Score,
          wickets: +scoreForm.team2Wickets || 0, overs: +scoreForm.team2Overs || 0,
        });
      }
      loadAll(); setShowScoreModal(false); showMsg('Score updated');
    } catch { showMsg('Failed to update score'); }
    setSaving(false);
  };

  const handleBatSubmit = async (e) => {
    e.preventDefault(); setSaving(true);
    try {
      await addBattingPerformance({ ...batForm, matchId: +id, runs: +batForm.runs, balls: +batForm.balls, fours: +batForm.fours, sixes: +batForm.sixes, battingOrder: +batForm.battingOrder, playerId: +batForm.playerId });
      loadAll(); setShowBatModal(false); showMsg('Batting performance added');
      setBatForm({ playerId: '', runs: 0, balls: 0, fours: 0, sixes: 0, isOut: false, dismissalType: 'Bowled', battingOrder: 1, inningsType: 'FIRST' });
    } catch { showMsg('Failed to add batting data'); }
    setSaving(false);
  };

  const handleBowlSubmit = async (e) => {
    e.preventDefault(); setSaving(true);
    try {
      await addBowlingPerformance({ ...bowlForm, matchId: +id, overs: +bowlForm.overs, maidens: +bowlForm.maidens, runsConceded: +bowlForm.runsConceded, wickets: +bowlForm.wickets, wides: +bowlForm.wides, noBalls: +bowlForm.noBalls, playerId: +bowlForm.playerId });
      loadAll(); setShowBowlModal(false); showMsg('Bowling performance added');
      setBowlForm({ playerId: '', overs: 0, maidens: 0, runsConceded: 0, wickets: 0, wides: 0, noBalls: 0, inningsType: 'FIRST' });
    } catch { showMsg('Failed to add bowling data'); }
    setSaving(false);
  };

  const quickScore = async (runs, isWide = false, isNoBall = false, label = '') => {
    if (!match) return;
    const inningsTeam = activeInnings === 'FIRST' ? 'team1' : 'team2';
    const currentScore = activeInnings === 'FIRST' ? (match.team1Score || 0) : (match.team2Score || 0);
    const currentWickets = activeInnings === 'FIRST' ? (match.team1Wickets || 0) : (match.team2Wickets || 0);
    const currentOvers = activeInnings === 'FIRST' ? (match.team1Overs || 0) : (match.team2Overs || 0);
    const newScore = currentScore + (isNoBall ? runs + 1 : runs);
    await updateScore(id, { team: inningsTeam, score: newScore, wickets: currentWickets, overs: currentOvers, status: 'LIVE' });
    addEvent(label || (isWide ? 'WD' : isNoBall ? 'NB' : String(runs)), runs);
    loadAll();
    showMsg(isWide ? `Wide +1` : isNoBall ? `No Ball +1` : `+${runs}`);
  };

  const quickWicket = async () => {
    if (!match) return;
    const inningsTeam = activeInnings === 'FIRST' ? 'team1' : 'team2';
    const currentScore = activeInnings === 'FIRST' ? (match.team1Score || 0) : (match.team2Score || 0);
    const currentWickets = activeInnings === 'FIRST' ? (match.team1Wickets || 0) : (match.team2Wickets || 0);
    const currentOvers = activeInnings === 'FIRST' ? (match.team1Overs || 0) : (match.team2Overs || 0);
    await updateScore(id, { team: inningsTeam, score: currentScore, wickets: Math.min(currentWickets + 1, 10), overs: currentOvers, status: 'LIVE' });
    addEvent('W', 0);
    loadAll(); showMsg('Wicket!');
  };

  if (loading) return <div className="loading"><div className="spinner" /><span>Loading match data...</span></div>;
  if (!match) return <div className="loading"><p>Match not found</p></div>;

  const isLive = match.status === 'LIVE';
  const allPlayers = [...team1Players, ...team2Players];
  const innings1 = scorecard?.firstInnings;
  const innings2 = scorecard?.secondInnings;
  const crr = activeInnings === 'FIRST'
    ? (match.team1Overs > 0 ? (match.team1Score / match.team1Overs).toFixed(2) : '-')
    : (match.team2Overs > 0 ? (match.team2Score / match.team2Overs).toFixed(2) : '-');
  const activeScore = activeInnings === 'FIRST' ? match.team1Score : match.team2Score;
  const activeWickets = activeInnings === 'FIRST' ? match.team1Wickets : match.team2Wickets;
  const activeOvers = activeInnings === 'FIRST' ? match.team1Overs : match.team2Overs;
  const reqRuns = match.team1Score != null && match.team2Score != null ? match.team1Score - match.team2Score + 1 : null;
  const remOvers = match.overs && match.team2Overs ? (match.overs - match.team2Overs).toFixed(1) : null;
  const winProb = match.team2Score != null && match.team1Score != null
    ? Math.max(5, Math.min(95, Math.round((match.team2Score / Math.max(match.team1Score, 1)) * 100)))
    : null;

  const activeBatting = (activeInnings === 'FIRST' ? innings1 : innings2)?.batting || [];
  const activeBowling = (activeInnings === 'FIRST' ? innings1 : innings2)?.bowling || [];
  const topBatter = activeBatting.sort((a, b) => b.runs - a.runs)[0];
  const topBowler = activeBowling.sort((a, b) => b.wickets - a.wickets)[0];

  return (
    <div className="live-console">
      {/* Live Score Header */}
      <div className="live-score-header">
        <div style={{ flex: 1, minWidth: 0 }}>
          <div className="live-badge-row">
            {isLive && <span className="badge badge-live">LIVE</span>}
            {match.status === 'COMPLETED' && <span className="badge badge-completed">FINAL</span>}
            <span className="live-match-name">{match.team1Name} vs {match.team2Name}</span>
          </div>
          <div style={{ display: 'flex', alignItems: 'baseline', gap: 0 }}>
            <span className="live-score-main">{activeScore ?? 0}/{activeWickets ?? 0}</span>
            <span className="live-score-overs">({activeOvers ?? 0} Overs)</span>
          </div>
        </div>

        <div className="live-stat-box">
          <div className="live-stat-label">CRR</div>
          <div className="live-stat-value">{crr}</div>
        </div>

        {match.team1Score != null && (
          <div className="live-stat-box">
            <div className="live-stat-label">Target</div>
            <div className="live-stat-value">{match.team1Score}</div>
          </div>
        )}

        {reqRuns > 0 && remOvers && (
          <div className="live-stat-box">
            <div className="live-stat-label">Need</div>
            <div className="live-stat-value">{reqRuns}</div>
            <div className="live-stat-sub">({remOvers} balls)</div>
          </div>
        )}

        {winProb != null && (
          <div className="live-stat-box">
            <div className="live-stat-label">Win Prob</div>
            <div className="live-stat-value highlight">{winProb}%</div>
          </div>
        )}

        <div style={{ marginLeft: 'auto', display: 'flex', gap: 8, flexShrink: 0 }}>
          <button className={`btn btn-sm ${autoRefresh ? 'btn-success' : 'btn-ghost'}`}
            onClick={() => setAutoRefresh(a => !a)}>
            {autoRefresh ? '⟳ Auto' : '⏸ Paused'}
          </button>
          <button className="btn btn-primary btn-sm" onClick={() => {
            setScoreForm({
              team1Score: match.team1Score ?? '', team1Wickets: match.team1Wickets ?? '',
              team1Overs: match.team1Overs ?? '', team2Score: match.team2Score ?? '',
              team2Wickets: match.team2Wickets ?? '', team2Overs: match.team2Overs ?? '',
              status: match.status || 'LIVE', tossWinnerId: '', tossDecision: match.tossDecision || 'BAT',
              winnerId: '', result: match.result || '', playerOfMatchId: ''
            });
            setShowScoreModal(true);
          }}>Update Score</button>
        </div>
      </div>

      {msg && (
        <div style={{ padding: '8px 20px', background: msg.includes('Failed') ? 'var(--red-muted)' : 'var(--accent-muted)', color: msg.includes('Failed') ? 'var(--red)' : 'var(--accent)', fontSize: 13, fontWeight: 600, borderBottom: '1px solid var(--card-border)' }}>
          {msg}
        </div>
      )}

      {/* 3-column body */}
      <div className="live-console-body">
        {/* LEFT: Add Event + Batting Pair */}
        <div className="lc-left">
          {/* Innings selector */}
          <div style={{ display: 'flex', gap: 6 }}>
            <button className={`btn btn-sm ${activeInnings === 'FIRST' ? 'btn-primary' : 'btn-ghost'}`}
              onClick={() => setActiveInnings('FIRST')}>
              {match.team1Name}
            </button>
            <button className={`btn btn-sm ${activeInnings === 'SECOND' ? 'btn-primary' : 'btn-ghost'}`}
              onClick={() => setActiveInnings('SECOND')}>
              {match.team2Name}
            </button>
          </div>

          {/* Add Event */}
          {isLive && (
            <div className="lc-panel">
              <div className="lc-panel-header">
                <span className="lc-panel-label">Add Event</span>
              </div>
              <div className="add-event-pad">
                <div className="event-grid">
                  <button className="event-btn" onClick={() => quickScore(1, false, false, '1')}>
                    <span className="event-btn-num">1</span>
                    <span className="event-btn-label">Run</span>
                  </button>
                  <button className="event-btn" onClick={() => quickScore(2, false, false, '2')}>
                    <span className="event-btn-num">2</span>
                    <span className="event-btn-label">Runs</span>
                  </button>
                  <button className="event-btn" onClick={() => quickScore(3, false, false, '3')}>
                    <span className="event-btn-num">3</span>
                    <span className="event-btn-label">Runs</span>
                  </button>
                  <button className="event-btn boundary" onClick={() => quickScore(4, false, false, '4')}>
                    <span className="event-btn-num">4</span>
                    <span className="event-btn-label">Boundary</span>
                  </button>
                  <button className="event-btn maximum" onClick={() => quickScore(6, false, false, '6')}>
                    <span className="event-btn-num">6</span>
                    <span className="event-btn-label">Maximum</span>
                  </button>
                  <button className="event-btn" onClick={() => quickScore(0, false, false, '0')}>
                    <span className="event-btn-num">0</span>
                    <span className="event-btn-label">Dot</span>
                  </button>
                </div>
                <div className="event-extras">
                  <button className="event-extra-btn" onClick={() => quickScore(0, true)}>
                    <span className="extra-code">WD</span> Wide
                  </button>
                  <button className="event-extra-btn" onClick={() => quickScore(0, false, true)}>
                    <span className="extra-code">NB</span> No Ball
                  </button>
                  <button className="event-extra-btn" onClick={() => quickScore(1, false, false, 'LB')}>
                    <span className="extra-code">LB</span> Leg Bye
                  </button>
                  <button className="event-btn wicket-btn" style={{ padding: '8px 6px' }} onClick={quickWicket}>
                    <span className="event-btn-num">✕</span>
                    <span className="event-btn-label">Wicket</span>
                  </button>
                </div>
              </div>
            </div>
          )}

          {/* Batting Pair */}
          <div className="lc-panel">
            <div className="lc-panel-header">
              <span className="lc-panel-label">Batting Pair</span>
              <button className="btn btn-ghost btn-sm" onClick={() => { setBatForm(f => ({ ...f, inningsType: activeInnings })); setShowBatModal(true); }}>
                + Add
              </button>
            </div>
            {activeBatting.length > 0 ? (
              activeBatting.slice(0, 2).map((b, i) => (
                <div key={b.id} className={`batter-row ${i === 0 ? 'on-strike' : ''}`}>
                  <div className={`batter-indicator ${i === 0 ? 'active' : ''}`} />
                  <div className="batter-info">
                    <div className="batter-name">
                      {b.playerName}
                      {i === 0 && <span className="strike-icon">⚡</span>}
                    </div>
                    <div className="batter-name-sub">{b.isOut ? b.dismissalType : 'Batting'}</div>
                  </div>
                  <div className="batter-stats">
                    <div style={{ textAlign: 'center' }}>
                      <div className="batter-stat-val">{b.runs}</div>
                      <div className="batter-stat-lbl">R</div>
                    </div>
                    <div style={{ textAlign: 'center' }}>
                      <div className="batter-stat-val" style={{ fontSize: 14, color: 'var(--text-2)' }}>{b.balls}</div>
                      <div className="batter-stat-lbl">B</div>
                    </div>
                    <div style={{ textAlign: 'center', display: 'none' }}>
                      <div className="batter-stat-val" style={{ fontSize: 13, color: 'var(--text-2)' }}>{b.strikeRate?.toFixed(0)}</div>
                      <div className="batter-stat-lbl">SR</div>
                    </div>
                  </div>
                  <button className="batter-swap-btn">⇄</button>
                </div>
              ))
            ) : (
              <div style={{ padding: '14px 16px', fontSize: 13, color: 'var(--text-3)' }}>
                No batting data yet
              </div>
            )}
            <div style={{ padding: '8px 14px', borderTop: '1px solid var(--card-border)' }}>
              <button className="btn btn-ghost btn-sm" style={{ width: '100%', justifyContent: 'center' }}>
                Manage Lineup
              </button>
            </div>
          </div>
        </div>

        {/* MIDDLE: Active Bowler + Scorecard */}
        <div className="lc-middle">
          {/* Active Bowler */}
          <div className="lc-panel">
            <div className="lc-panel-header">
              <span className="lc-panel-label">Active Bowler</span>
              <button className="btn btn-ghost btn-sm" onClick={() => { setBowlForm(f => ({ ...f, inningsType: activeInnings })); setShowBowlModal(true); }}>
                ✏
              </button>
            </div>
            {topBowler ? (
              <>
                <div className="bowler-row">
                  <div className="bowler-dot" />
                  <div className="bowler-info">
                    <div className="bowler-name">{topBowler.playerName}</div>
                    <div className="bowler-figures">
                      {topBowler.overs} - {topBowler.maidens} - {topBowler.runsConceded} - {topBowler.wickets} · Econ {topBowler.economy?.toFixed(1)}
                    </div>
                  </div>
                </div>
                <div className="this-over-label">This Over</div>
                <div className="over-balls">
                  {lastEvents.slice(-5).map((e, i) => (
                    <div key={i} className={`over-ball ${e.label === '4' ? 'four' : e.label === '6' ? 'six' : e.label === 'W' ? 'wicket' : e.label === '0' ? 'dot' : ''}`}>
                      {e.label}
                    </div>
                  ))}
                  <div className="over-ball next">-</div>
                </div>
              </>
            ) : (
              <div style={{ padding: '14px 16px', fontSize: 13, color: 'var(--text-3)' }}>
                No bowling data yet
              </div>
            )}
          </div>

          {/* Mini Scorecard */}
          {[
            { label: '1st Innings', innings: innings1, team: match.team1Name },
            { label: '2nd Innings', innings: innings2, team: match.team2Name },
          ].map(({ label, innings, team }) => innings && (
            <div key={label} className="lc-panel">
              <div className="lc-panel-header">
                <span className="lc-panel-label">{team} — {label}</span>
              </div>
              {innings.batting?.length > 0 && (
                <div className="sc-table-wrap">
                  <table className="sc-table">
                    <thead><tr>
                      <th>Batter</th><th className="right">R</th><th className="right">B</th>
                      <th className="right">4s</th><th className="right">6s</th><th className="right">SR</th>
                    </tr></thead>
                    <tbody>
                      {innings.batting.map(b => (
                        <tr key={b.id} className={!b.isOut ? 'on-strike' : ''}>
                          <td style={{ fontWeight: b.runs >= 50 ? 700 : 400 }}>{b.playerName}{!b.isOut && '*'}</td>
                          <td className="right" style={{ fontFamily: 'Rajdhani', fontSize: 15, fontWeight: 700, color: b.runs >= 50 ? 'var(--accent)' : 'inherit' }}>{b.runs}</td>
                          <td className="right" style={{ color: 'var(--text-3)' }}>{b.balls}</td>
                          <td className="right" style={{ color: 'var(--green)' }}>{b.fours}</td>
                          <td className="right" style={{ color: 'var(--accent)' }}>{b.sixes}</td>
                          <td className="right" style={{ color: 'var(--text-3)' }}>{b.strikeRate?.toFixed(0)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
              {innings.bowling?.length > 0 && (
                <div className="sc-table-wrap" style={{ borderTop: '1px solid var(--card-border)' }}>
                  <table className="sc-table">
                    <thead><tr>
                      <th>Bowler</th><th className="right">O</th><th className="right">M</th>
                      <th className="right">R</th><th className="right">W</th><th className="right">ER</th>
                    </tr></thead>
                    <tbody>
                      {innings.bowling.map(b => (
                        <tr key={b.id}>
                          <td style={{ fontWeight: b.wickets >= 3 ? 700 : 400, color: b.wickets >= 3 ? 'var(--accent)' : 'inherit' }}>{b.playerName}</td>
                          <td className="right" style={{ color: 'var(--text-3)' }}>{b.overs}</td>
                          <td className="right" style={{ color: 'var(--text-3)' }}>{b.maidens}</td>
                          <td className="right">{b.runsConceded}</td>
                          <td className="right" style={{ color: b.wickets >= 3 ? 'var(--green)' : 'inherit', fontWeight: b.wickets >= 3 ? 700 : 400 }}>{b.wickets}</td>
                          <td className="right" style={{ color: 'var(--text-3)' }}>{b.economy?.toFixed(2)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
              {(!innings.batting?.length && !innings.bowling?.length) && (
                <div style={{ padding: '14px 16px', fontSize: 13, color: 'var(--text-3)' }}>No performance data recorded yet</div>
              )}
            </div>
          ))}
        </div>

        {/* RIGHT: Scorecard Preview + Timeline */}
        <div className="lc-right">
          <div className="sc-header">
            <span className="sc-label">Scorecard Preview</span>
            <button className="live-feedback-btn">Live Feedback</button>
          </div>

          {/* Compact batter table */}
          {activeBatting.length > 0 && (
            <div>
              <div className="sc-table-wrap">
                <table className="sc-table">
                  <thead><tr>
                    <th>Batter</th><th className="right">R</th><th className="right">B</th>
                    <th className="right">4s</th><th className="right">6s</th><th className="right">SR</th>
                  </tr></thead>
                  <tbody>
                    {activeBatting.slice(0, 3).map(b => (
                      <tr key={b.id} className={!b.isOut ? 'on-strike' : ''}>
                        <td>{b.playerName}{!b.isOut && '*'}</td>
                        <td className="right" style={{ fontFamily: 'Rajdhani', fontWeight: 700 }}>{b.runs}</td>
                        <td className="right" style={{ color: 'var(--text-3)' }}>{b.balls}</td>
                        <td className="right" style={{ color: 'var(--green)' }}>{b.fours}</td>
                        <td className="right" style={{ color: 'var(--accent)' }}>{b.sixes}</td>
                        <td className="right" style={{ color: 'var(--text-3)' }}>{b.strikeRate?.toFixed(1)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Extras */}
              <div style={{ padding: '8px 14px', fontSize: 12, color: 'var(--text-3)', borderBottom: '1px solid var(--card-border)' }}>
                Extras: <span style={{ color: 'var(--text-2)' }}>
                  {(scorecard?.firstInnings?.wides || 0) + (scorecard?.firstInnings?.noBalls || 0)} total
                </span>
              </div>
            </div>
          )}

          {/* Bowler table */}
          {activeBowling.length > 0 && (
            <div className="sc-table-wrap">
              <table className="sc-table">
                <thead><tr>
                  <th>Bowler</th><th className="right">O</th><th className="right">M</th>
                  <th className="right">R</th><th className="right">W</th><th className="right">ER</th>
                </tr></thead>
                <tbody>
                  {activeBowling.slice(0, 3).map(b => (
                    <tr key={b.id}>
                      <td style={{ color: b.wickets >= 3 ? 'var(--accent)' : 'inherit' }}>{b.playerName}</td>
                      <td className="right" style={{ color: 'var(--text-3)' }}>{b.overs}</td>
                      <td className="right" style={{ color: 'var(--text-3)' }}>{b.maidens}</td>
                      <td className="right">{b.runsConceded}</td>
                      <td className="right" style={{ color: b.wickets >= 3 ? 'var(--green)' : 'inherit' }}>{b.wickets}</td>
                      <td className="right" style={{ color: 'var(--text-3)' }}>{b.economy?.toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Innings Timeline */}
          <div className="innings-timeline">
            <div className="timeline-label">Innings Timeline</div>
            {lastEvents.length > 0 ? [...lastEvents].reverse().map((e, i) => (
              <div key={i} className="timeline-item">
                <div className={`timeline-dot ${e.label === '4' || e.label === '6' ? 'notable' : e.label === 'W' ? 'wicket-dot' : ''}`} />
                <div style={{ flex: 1 }}>
                  <div className="timeline-over">{e.time} | Ball</div>
                  <div className="timeline-desc">
                    {e.label === 'W' ? 'Wicket fell!' : e.label === '6' ? 'Huge hit over the boundary for six!' : e.label === '4' ? 'Driven to the boundary for four!' : e.label === 'WD' ? 'Wide ball called.' : e.label === 'NB' ? 'No ball called.' : `${e.label} run${e.label !== '1' ? 's' : ''} taken.`}
                  </div>
                </div>
                <div className="timeline-runs">{e.label === 'W' ? 'W' : `${e.runs} runs`}</div>
              </div>
            )) : (
              <div style={{ padding: '16px 14px', fontSize: 13, color: 'var(--text-3)' }}>
                Ball-by-ball events will appear here
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Bottom Bar */}
      <div className="live-console-footer">
        <button className="footer-action-btn" onClick={() => showMsg('Last ball undone (demo)')}>
          ↩ Undo Last Ball
        </button>
        <button className="footer-action-btn" onClick={() => setAutoRefresh(a => !a)}>
          ⏸ {autoRefresh ? 'Pause' : 'Resume'} Match
        </button>
        <div className="footer-status">
          <div className="status-dot" />
          <span>Status:</span>
          <span className="footer-status-text">{isLive ? 'Synchronized' : match.status}</span>
        </div>
        <button className="footer-action-btn" onClick={() => setShowScoreModal(true)}>
          Match Settings
        </button>
        <Link to={`/matches/${id}/scorecard`} className="footer-action-btn" style={{ textDecoration: 'none' }} target="_blank">
          Review Log
        </Link>
      </div>

      {/* Score Update Modal */}
      {showScoreModal && (
        <div className="modal-backdrop" onClick={e => e.target === e.currentTarget && setShowScoreModal(false)}>
          <div className="modal modal-lg">
            <div className="modal-header">
              <div className="modal-title">Update Match Score</div>
              <button className="close-btn" onClick={() => setShowScoreModal(false)}>×</button>
            </div>
            <form onSubmit={handleScoreUpdate}>
              <div className="modal-body">
                <div className="form-row" style={{ marginBottom: 20 }}>
                  <div className="form-group" style={{ margin: 0 }}>
                    <label className="form-label">Match Status</label>
                    <select className="form-select" value={scoreForm.status} onChange={e => setScoreForm(f => ({ ...f, status: e.target.value }))}>
                      <option value="SCHEDULED">Scheduled</option>
                      <option value="LIVE">Live</option>
                      <option value="COMPLETED">Completed</option>
                    </select>
                  </div>
                  <div className="form-group" style={{ margin: 0 }}>
                    <label className="form-label">Toss Decision</label>
                    <select className="form-select" value={scoreForm.tossDecision} onChange={e => setScoreForm(f => ({ ...f, tossDecision: e.target.value }))}>
                      <option value="BAT">Elected to Bat</option>
                      <option value="BOWL">Elected to Bowl</option>
                    </select>
                  </div>
                </div>
                <div className="divider-label">1st Innings — {match.team1Name}</div>
                <div className="form-row-3">
                  <div className="form-group">
                    <label className="form-label">Score (Runs)</label>
                    <input className="form-input" type="number" min="0" placeholder="e.g. 185" value={scoreForm.team1Score} onChange={e => setScoreForm(f => ({ ...f, team1Score: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Wickets</label>
                    <input className="form-input" type="number" min="0" max="10" placeholder="0–10" value={scoreForm.team1Wickets} onChange={e => setScoreForm(f => ({ ...f, team1Wickets: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Overs</label>
                    <input className="form-input" type="number" step="0.1" min="0" placeholder="e.g. 18.4" value={scoreForm.team1Overs} onChange={e => setScoreForm(f => ({ ...f, team1Overs: e.target.value }))} />
                  </div>
                </div>
                <div className="divider-label">2nd Innings — {match.team2Name}</div>
                <div className="form-row-3">
                  <div className="form-group">
                    <label className="form-label">Score (Runs)</label>
                    <input className="form-input" type="number" min="0" placeholder="e.g. 140" value={scoreForm.team2Score} onChange={e => setScoreForm(f => ({ ...f, team2Score: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Wickets</label>
                    <input className="form-input" type="number" min="0" max="10" placeholder="0–10" value={scoreForm.team2Wickets} onChange={e => setScoreForm(f => ({ ...f, team2Wickets: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Overs</label>
                    <input className="form-input" type="number" step="0.1" min="0" placeholder="e.g. 16.2" value={scoreForm.team2Overs} onChange={e => setScoreForm(f => ({ ...f, team2Overs: e.target.value }))} />
                  </div>
                </div>
                {scoreForm.status === 'COMPLETED' && (
                  <>
                    <div className="divider-label">Match Result</div>
                    <div className="form-row">
                      <div className="form-group">
                        <label className="form-label">Winner</label>
                        <select className="form-select" value={scoreForm.winnerId} onChange={e => setScoreForm(f => ({ ...f, winnerId: e.target.value }))}>
                          <option value="">— No result / Tie —</option>
                          <option value={match.team1Id}>{match.team1Name}</option>
                          <option value={match.team2Id}>{match.team2Name}</option>
                        </select>
                      </div>
                      <div className="form-group">
                        <label className="form-label">Player of the Match</label>
                        <select className="form-select" value={scoreForm.playerOfMatchId} onChange={e => setScoreForm(f => ({ ...f, playerOfMatchId: e.target.value }))}>
                          <option value="">— Select player —</option>
                          {allPlayers.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                        </select>
                      </div>
                    </div>
                    <div className="form-group">
                      <label className="form-label">Result Description</label>
                      <input className="form-input" placeholder="e.g. CSK won by 45 runs" value={scoreForm.result} onChange={e => setScoreForm(f => ({ ...f, result: e.target.value }))} />
                    </div>
                  </>
                )}
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-ghost" onClick={() => setShowScoreModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Saving...' : 'Update Score'}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Batting Modal */}
      {showBatModal && (
        <div className="modal-backdrop" onClick={e => e.target === e.currentTarget && setShowBatModal(false)}>
          <div className="modal modal-md">
            <div className="modal-header">
              <div className="modal-title">Batting Performance</div>
              <button className="close-btn" onClick={() => setShowBatModal(false)}>×</button>
            </div>
            <form onSubmit={handleBatSubmit}>
              <div className="modal-body">
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Batter</label>
                    <select className="form-select" required value={batForm.playerId} onChange={e => setBatForm(f => ({ ...f, playerId: e.target.value }))}>
                      <option value="">— Select batter —</option>
                      {allPlayers.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                    </select>
                  </div>
                  <div className="form-group">
                    <label className="form-label">Innings</label>
                    <select className="form-select" value={batForm.inningsType} onChange={e => setBatForm(f => ({ ...f, inningsType: e.target.value }))}>
                      <option value="FIRST">1st Innings</option>
                      <option value="SECOND">2nd Innings</option>
                    </select>
                  </div>
                </div>
                <div className="form-row-3">
                  <div className="form-group">
                    <label className="form-label">Runs</label>
                    <input className="form-input" type="number" min="0" value={batForm.runs} onChange={e => setBatForm(f => ({ ...f, runs: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Balls</label>
                    <input className="form-input" type="number" min="0" value={batForm.balls} onChange={e => setBatForm(f => ({ ...f, balls: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Bat Order</label>
                    <input className="form-input" type="number" min="1" max="11" value={batForm.battingOrder} onChange={e => setBatForm(f => ({ ...f, battingOrder: e.target.value }))} />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">4s</label>
                    <input className="form-input" type="number" min="0" value={batForm.fours} onChange={e => setBatForm(f => ({ ...f, fours: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">6s</label>
                    <input className="form-input" type="number" min="0" value={batForm.sixes} onChange={e => setBatForm(f => ({ ...f, sixes: e.target.value }))} />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginTop: 8 }}>
                      <input type="checkbox" id="isOut" checked={batForm.isOut} onChange={e => setBatForm(f => ({ ...f, isOut: e.target.checked }))} style={{ width: 16, height: 16 }} />
                      <label htmlFor="isOut" style={{ fontSize: 13 }}>Player got out</label>
                    </div>
                  </div>
                  {batForm.isOut && (
                    <div className="form-group">
                      <label className="form-label">Dismissal Type</label>
                      <select className="form-select" value={batForm.dismissalType} onChange={e => setBatForm(f => ({ ...f, dismissalType: e.target.value }))}>
                        {DISMISSAL_TYPES.map(d => <option key={d}>{d}</option>)}
                      </select>
                    </div>
                  )}
                </div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-ghost" onClick={() => setShowBatModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Saving...' : 'Save Performance'}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Bowling Modal */}
      {showBowlModal && (
        <div className="modal-backdrop" onClick={e => e.target === e.currentTarget && setShowBowlModal(false)}>
          <div className="modal modal-md">
            <div className="modal-header">
              <div className="modal-title">Bowling Performance</div>
              <button className="close-btn" onClick={() => setShowBowlModal(false)}>×</button>
            </div>
            <form onSubmit={handleBowlSubmit}>
              <div className="modal-body">
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Bowler</label>
                    <select className="form-select" required value={bowlForm.playerId} onChange={e => setBowlForm(f => ({ ...f, playerId: e.target.value }))}>
                      <option value="">— Select bowler —</option>
                      {allPlayers.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                    </select>
                  </div>
                  <div className="form-group">
                    <label className="form-label">Innings</label>
                    <select className="form-select" value={bowlForm.inningsType} onChange={e => setBowlForm(f => ({ ...f, inningsType: e.target.value }))}>
                      <option value="FIRST">1st Innings</option>
                      <option value="SECOND">2nd Innings</option>
                    </select>
                  </div>
                </div>
                <div className="form-row-3">
                  <div className="form-group">
                    <label className="form-label">Overs</label>
                    <input className="form-input" type="number" step="0.1" min="0" value={bowlForm.overs} onChange={e => setBowlForm(f => ({ ...f, overs: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Maidens</label>
                    <input className="form-input" type="number" min="0" value={bowlForm.maidens} onChange={e => setBowlForm(f => ({ ...f, maidens: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Runs</label>
                    <input className="form-input" type="number" min="0" value={bowlForm.runsConceded} onChange={e => setBowlForm(f => ({ ...f, runsConceded: e.target.value }))} />
                  </div>
                </div>
                <div className="form-row-3">
                  <div className="form-group">
                    <label className="form-label">Wickets</label>
                    <input className="form-input" type="number" min="0" max="10" value={bowlForm.wickets} onChange={e => setBowlForm(f => ({ ...f, wickets: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Wides</label>
                    <input className="form-input" type="number" min="0" value={bowlForm.wides} onChange={e => setBowlForm(f => ({ ...f, wides: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">No Balls</label>
                    <input className="form-input" type="number" min="0" value={bowlForm.noBalls} onChange={e => setBowlForm(f => ({ ...f, noBalls: e.target.value }))} />
                  </div>
                </div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-ghost" onClick={() => setShowBowlModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Saving...' : 'Save Performance'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
